var aButton = global.get("aButton"); 
node.warn("aButton is: " + aButton);

if (aButton === true) {                     
    // We negeren deze payload volledig omdat dit het antwoord/echo is van het SET-commando!
    node.warn("Meting overgeslagen om buffer-vervuiling te voorkomen.");

    // Zet de blokkering weer uit voor de volgende reguliere meting over 3 seconden
    global.set("aButton", false); 

    // Stop de flow hier direct, stuur niets door naar SignalK
    return null; 
}

// function to calculate checksum
function chksum(buffer, len) {
    let checksum = 0;
    let ii;
    for (ii = 0; ii < len; ii++) {
        checksum = checksum + buffer[ii];
    }
return checksum;
}

// function to calculate cells diff
function maxAbsDiff(arr, n) {
    arr.sort(function (a, b) { return a - b });
    return arr[n - 1] - arr[0];
}

// verify the reply from BMS if it has the right header
msg.error = null;
msg.buffer = msg.payload;
if (msg.buffer[0] != 0x4E || msg.buffer[1] != 0x57) {
    node.warn ('Invalid header');
    msg.error = "BMS Error";
}

// verify the reply from BMS if it has the right checksum
msg.jkbms = {};
msg.jkbms.data_len = msg.buffer[2] << 8 | msg.buffer[3] << 0;
msg.jkbms.function = msg.buffer[8];
msg.jkbms.computed_crc = chksum(msg.buffer, msg.jkbms.data_len);

msg.jkbms.bmsreply_crc = msg.buffer[msg.jkbms.data_len] << 8 | msg.buffer[msg.jkbms.data_len + 1] << 0;

if (msg.jkbms.computed_crc != msg.jkbms.bmsreply_crc) {
    node.warn('JkModbus CRC Check failed!');
    msg.error = "BMS Error";
}

//cell voltages
const cells = [];
let cell;
msg.jkbms.numberOfCells = msg.buffer[12] / 3;
msg.jkbms.cell_voltages = {};
for (cell = 1; cell <= msg.jkbms.numberOfCells; cell++) {
    msg.jkbms.cell_voltages["cell" + cell] = (msg.buffer[12 + cell * 3 - 1] << 8 | msg.buffer[12 + cell * 3] << 0) / 1000;
    cells[cell-1] = msg.jkbms.cell_voltages["cell" + cell]
}

// cell diff voltage
msg.jkbms.cell_diff = parseFloat(maxAbsDiff(cells, 4).toFixed(3));

// cell min & max
//msg.jkbms.cell_min = Math.min.apply(Math, cells).toFixed(3);
msg.jkbms.cell_min = parseFloat(Math.min.apply(Math, cells).toFixed(3));
//msg.jkbms.cell_max = Math.max.apply(Math, cells).toFixed(3);
msg.jkbms.cell_max = parseFloat(Math.max.apply(Math, cells).toFixed(3));

//temperatures
msg.jkbms.temperatures = {};
//if (msg.buffer[25] != 0x80) {
//    node.warn ('Temperatures marker not correct!');
//    msg.error = "BMS Error";
//}
msg.jkbms.temperatures.internal = msg.buffer[26] << 8 | msg.buffer[27] << 0;
if (msg.jkbms.temperatures.internal > 100) {
    msg.jkbms.temperatures.internal = msg.jkbms.temperatures.internal - 100;
}
msg.jkbms.temperatures.battery1 = msg.buffer[29] << 8 | msg.buffer[30] << 0;
if (msg.jkbms.temperatures.battery1 > 100) {
    msg.jkbms.temperatures.battery1 = msg.jkbms.temperatures.battery1 - 100;
}
msg.jkbms.temperatures.battery2 = msg.buffer[32] << 8 | msg.buffer[33] << 0;
if (msg.jkbms.temperatures.battery2 > 100) {
    msg.jkbms.temperatures.battery2 = msg.jkbms.temperatures.battery2 - 100;
}

//battery voltage
//if (msg.buffer[34] != 0x83) {
//    node.warn ('Voltage marker not correct!');
//    msg.error = "BMS Error";
//}
msg.jkbms.voltage = (msg.buffer[35] << 8 | msg.buffer[36] << 0) / 100;

//battery current
//if (msg.buffer[37] != 0x84) {
//    node.warn ('Current marker not correct!');
//   msg.error = "BMS Error";
//}
msg.jkbms.current = (msg.buffer[38] << 8 | msg.buffer[39] << 0);

let currconst = 32768
if (msg.jkbms.current < currconst)
    msg.jkbms.current = msg.jkbms.current / -100;
else
    msg.jkbms.current = (msg.jkbms.current - currconst) / 100;

//remainig battery SOC
//if (msg.buffer[40] != 0x85) {
//    node.warn ('Remaining battery SOC marker not correct!');
//    msg.error = "BMS Error";
//}
msg.jkbms.remainingsoc = msg.buffer[41];

//numberof NTC
//if (msg.buffer[42] != 0x86) {
//    node.warn ('Number of NTC marker not correct!');
//   msg.error = "BMS Error";
//}
msg.jkbms.ntcnumber = msg.buffer[43];

//numberof battery cycles
//if (msg.buffer[44] != 0x87) {
//    node.warn ('Number of battery cycles marker not correct!');
//    msg.error = "BMS Error";
//}
msg.jkbms.batterycycles = (msg.buffer[45] << 8 | msg.buffer[46] << 0);

//battery cycle capacity Ah
//if (msg.buffer[47] != 0x89) {
//    node.warn ('Battery cycle capacity Ah marker not correct!');
//    msg.error = "BMS Error";
//}
msg.jkbms.batterycyclecapacity = (msg.buffer[48] << 24 | msg.buffer[49] << 16 | msg.buffer[50] << 8 | msg.buffer[51] << 0);

//number of cells
//if (msg.buffer[52] != 0x8a) {
//    node.warn ('Number of cells marker not correct!');
//    msg.error = "BMS Error";
//}
msg.jkbms.cellsnumber = (msg.buffer[53] << 8 | msg.buffer[54] << 0);

// battery capacity setting
//if (msg.buffer[143] != 0xaa) {
//    node.warn('Battery capacity marker not correct!');
//    msg.error = "BMS Error";
//}
msg.jkbms.batterycapacity = (msg.buffer[144] << 24 | msg.buffer[145] << 16 | msg.buffer[146] << 8 | msg.buffer[147] << 0);

//battery warnings
msg.jkbms.warnings = {};

//if (msg.buffer[55] != 0x8b) {
//    node.warn ('Battery warnings marker not correct!');
//    msg.error = "BMS Error";
//}
msg.jkbms.warnings.batteryWarning = (msg.buffer[56] << 8 | msg.buffer[57] << 0);

msg.jkbms.warnings.lowCapacity = msg.jkbms.warnings.batteryWarning & 1;
msg.jkbms.warnings.powerTubeOvertemperature = (msg.jkbms.warnings.batteryWarning & 2) >> 1 ;
msg.jkbms.warnings.chargingOvervoltage = (msg.jkbms.warnings.batteryWarning & 4) >> 2;
msg.jkbms.warnings.dischargingUndervoltage = (msg.jkbms.warnings.batteryWarning & 8) >> 3;
msg.jkbms.warnings.batteryOvertemperature = (msg.jkbms.warnings.batteryWarning & 16) >> 4;
msg.jkbms.warnings.chargingOvercurrent = (msg.jkbms.warnings.batteryWarning & 32) >> 5;
msg.jkbms.warnings.dischargingOvercurrent = (msg.jkbms.warnings.batteryWarning & 64) >> 6;
msg.jkbms.warnings.cellPressureDifference = (msg.jkbms.warnings.batteryWarning & 128) >> 7;
msg.jkbms.warnings.overtemperatureBatteryBox = (msg.jkbms.warnings.batteryWarning & 256) >> 8;
msg.jkbms.warnings.batteryLowtemperature = (msg.jkbms.warnings.batteryWarning & 512) >> 9;
msg.jkbms.warnings.cellOvervoltage = (msg.jkbms.warnings.batteryWarning & 1024) >> 10;
msg.jkbms.warnings.cellUndervoltage = (msg.jkbms.warnings.batteryWarning & 2048) >> 11;
msg.jkbms.warnings.alarm309_AProtection = (msg.jkbms.warnings.batteryWarning & 4096) >> 12;
msg.jkbms.warnings.alarm309_BProtection = (msg.jkbms.warnings.batteryWarning & 8192) >> 13;

//battery status
msg.jkbms.status = {};

//if (msg.buffer[58] != 0x8c) {
//    node.warn ('Battery warning marker not correct!');
//    msg.error = "BMS Error";
//}
msg.jkbms.status.batteryStatus = (msg.buffer[59] << 8 | msg.buffer[60] << 0);
msg.jkbms.status.chargingEnabled = msg.jkbms.status.batteryStatus & 1;
msg.jkbms.status.dischargingEnabled = (msg.jkbms.status.batteryStatus & 2) >> 1;
msg.jkbms.status.balancingEnabled = (msg.jkbms.status.batteryStatus & 4) >> 2;
msg.jkbms.status.emergencyConnect = (msg.jkbms.status.batteryStatus & 8) >> 3;

return msg;

msg.topic = "electrical.batteries.house.LiFePO4.remaining-ah";
msg.payload = msg.jkbms.batterycapacity * msg.jkbms.remainingsoc / 100;
return msg;

// Omdat KIP als boolean geen "0" en "1" snapt
// wordt dat hier omgezet in false en true.

msg.topic = "electrical.batteries.house.LiFePO4.allow2discharge";
var check = msg.jkbms.status.dischargingEnabled;
//node.warn("check is: " +check);

if (check === 0) {
    msg.payload = false;
}

if (check === 1) {
    msg.payload = true;
}

return msg;

// Omdat KIP als boolean geen "0" en "1" snapt
// wordt dat hier omgezet in false en true.

msg.topic = "electrical.batteries.house.LiFePO4.balancing";
var check = msg.jkbms.status.balancingEnabled;

if (check == 0) {
    msg.payload = false;
}

if (check == 1) {
    msg.payload = true;
}

return msg;

// Omdat KIP als boolean geen "0" en "1" snapt
// wordt dat hier omgezet in false en true.

msg.topic = "electrical.batteries.house.LiFePO4.allow2charge";
var check = msg.jkbms.status.chargingEnabled;

if (check === 0) {
    msg.payload = false;
    //node.status({ fill: "red", shape: "ring", text: "cFET: false" });
}

if (check === 1) {
    msg.payload = true;
    //node.status({ fill: "green", shape: "dot", text: "cFET: true" });
}
return msg;

if (msg.payload === false) {
  global.set("cFET",false);
}

if (msg.payload === true) {
    global.set("cFET",true);
}

global.set("setSwitchc",true);
return msg;

if (msg.payload === false) {
  global.set("dcFET",false);
}

if (msg.payload === true) {
    global.set("dcFET",true);
}

global.set("setSwitchdc",true);
return msg;

msg.timeout = 10000;

var charge = global.get("cFET");
var discharge = global.get("dcFET");
var Switchc = global.get("setSwitchc");
var Switchdc = global.get("setSwitchdc");

// Als de subglobal aangeeft dat een schakelaar is omgezet
if (Switchc === true || Switchdc === true) {    

  // Verwerk laadschakelaar (cFET)
  if (Switchc === true) {
    // Wis de switch trigger voor de volgende cyclus
    global.set("setSwitchc", undefined); 

    if (charge === false) {
      // Stuur commando: cFET fysiek UIT (eindigt op 0x00 ... 0xd3)
      msg.payload = Buffer.from([0x4E, 0x57, 0x00, 0x14, 0x00, 0x00, 0x00, 0x00, 0x02, 0x03, 0x02, 0xab, 0x00, 0x00, 0x00, 0x00, 0x00, 0x68, 0x00, 0x00, 0x01, 0xd3]);
      node.warn("Fysiek commando verzonden: cFET UIT");
    } else if (charge === true) {
      // Stuur commando: cFET fysiek AAN (eindigt op 0x01 ... 0xd4)
      msg.payload = Buffer.from([0x4E, 0x57, 0x00, 0x14, 0x00, 0x00, 0x00, 0x00, 0x02, 0x03, 0x02, 0xab, 0x01, 0x00, 0x00, 0x00, 0x00, 0x68, 0x00, 0x00, 0x01, 0xd4]);
      node.warn("Fysiek commando verzonden: cFET AAN");
    }
  }

  // Verwerk ontlaadschakelaar (dcFET)
  if (Switchdc === true) {
    // Wis de switch trigger voor de volgende cyclus
    global.set("setSwitchdc", undefined); 

    if (discharge === false) {
      // Stuur commando: dcFET fysiek UIT (eindigt op 0x00 ... 0xd4)
      msg.payload = Buffer.from([0x4E, 0x57, 0x00, 0x14, 0x00, 0x00, 0x00, 0x00, 0x02, 0x03, 0x02, 0xac, 0x00, 0x00, 0x00, 0x00, 0x00, 0x68, 0x00, 0x00, 0x01, 0xd4]);
      node.warn("Fysiek commando verzonden: dcFET UIT");
    } else if (discharge === true) {
      // Stuur commando: dcFET fysiek AAN (eindigt op 0x01 ... 0xd5)
      msg.payload = Buffer.from([0x4E, 0x57, 0x00, 0x14, 0x00, 0x00, 0x00, 0x00, 0x02, 0x03, 0x02, 0xac, 0x01, 0x00, 0x00, 0x00, 0x00, 0x68, 0x00, 0x00, 0x01, 0xd5]);
      node.warn("Fysiek commando verzonden: dcFET AAN");
    }
  }

  node.warn("charge is: " +charge);
  node.warn("discharge is: " +discharge);
  node.warn("ZETTEN");
  global.set("aButton",true);
} else {      
  // Reguliere LEZEN cyclus (elke 3 seconden)
  node.warn("LEZEN");
  msg.payload = Buffer.from([0x4E, 0x57, 0x00, 0x13, 0x00, 0x00, 0x00, 0x00, 0x06, 0x03, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x68, 0x00, 0x00, 0x01, 0x29]);
}

return msg;
